package org.apache.commons.compress.archivers.zip;

import org.junit.runner.RunWith;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = {"org.apache.commons.compress.archivers.zip.steps"},
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.zip.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import org.apache.commons.compress.archivers.ArchiveEntry;
import org.apache.commons.compress.archivers.zip.ZipArchiveInputStream;
import java.util.zip.ZipException;

public class StepDefs {

    private ZipArchiveInputStream zipInputStream;
    private ArchiveEntry entry;
    private Exception exception;
    private InputStream inputStream;

    @Given("a ZipArchiveInputStream is initialized with an input stream containing data that is not a valid zip archive \\(e\\.g\\. an XML file)")
    public void given_a_zip_archive_input_stream_is_initialized_with_invalid_data() {
        String xmlData = "<?xml version=\"1.0\" encoding=\"UTF-8\"?><invalid>not a zip file</invalid>";
        byte[] xmlBytes = xmlData.getBytes();
        inputStream = new ByteArrayInputStream(xmlBytes);
    }

    @Given("the stream provides enough data to read a Local File Header")
    public void given_stream_provides_enough_data() {
        // The XML data already provides enough data to trigger validation
    }

    @When("I call \"getNextEntry\" or \"getNextZipEntry\" to retrieve the first entry")
    public void when_i_call_get_next_entry() {
        try {
            zipInputStream = new ZipArchiveInputStream(inputStream);
            entry = zipInputStream.getNextEntry(); // This should trigger the validation
        } catch (IOException e) {
            exception = e;
        }
    }

    @Then("the method should throw a \"ZipException\" indicating that the stream is not a valid zip archive")
    public void then_method_should_throw_zip_exception() {
        assertNotNull("Expected an exception to be thrown", exception);
        assertTrue("Expected exception to be a ZipException or IOException wrapping ZipException",
                   exception instanceof ZipException ||
                   (exception instanceof IOException && exception.getCause() instanceof ZipException));
        assertTrue("Exception message should indicate invalid zip archive",
                   exception.getMessage() != null &&
                   (exception.getMessage().toLowerCase().contains("zip") ||
                    exception.getMessage().toLowerCase().contains("archive") ||
                    exception.getMessage().toLowerCase().contains("invalid")));
    }
}

