import org.apache.commons.compress.archivers.zip.ZipArchiveInputStream;
import org.junit.Test;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.util.zip.ZipException;

import static org.junit.Assert.*;

public class TestNonZipData {
    @Test
    public void testNonZipDataShouldThrowException() throws IOException {
        String xmlData = "<?xml version=\"1.0\" encoding=\"UTF-8\"?><invalid>not a zip file</invalid>";
        byte[] xmlBytes = xmlData.getBytes();
        ByteArrayInputStream inputStream = new ByteArrayInputStream(xmlBytes);

        ZipArchiveInputStream zipInputStream = new ZipArchiveInputStream(inputStream);

        try {
            zipInputStream.getNextEntry();
            fail("Expected ZipException to be thrown for non-ZIP data");
        } catch (ZipException e) {
            assertTrue("Exception message should indicate invalid zip archive",
                       e.getMessage().contains("Not a zip archive"));
        } finally {
            zipInputStream.close();
        }
    }
}

